INSERT INTO collection_items (id, section, data, sort_order) VALUES (51, 'certificates', '{"image":"/uploads/certificate1.png","title":"Appreciation for Excellent Serving Towards Society","issuer":"Delhi Police — Station House Officer, Delhi Cantt","date":"June 2026","description":"Delhi Police commends Punjabi Welfare Trust for serving the community through educational support, awareness programs, free NDA coaching and library facilities, recognising its commitment to empowering youth and promoting social responsibility."}', 0) ON DUPLICATE KEY UPDATE data = VALUES(data), sort_order = VALUES(sort_order);
INSERT INTO collection_items (id, section, data, sort_order) VALUES (52, 'certificates', '{"image":"/uploads/certificate2.png","title":"Appreciation for Outstanding Social Service","issuer":"Indian Army — HQ Technical Group EME, Delhi Cantt","date":"June 2026","description":"Col Vikas Tomar, CIME (IM & NSC), acknowledges the commendable efforts of the Trust in serving society through educational and awareness initiatives that will go a long way in shaping the future of the young generation."}', 1) ON DUPLICATE KEY UPDATE data = VALUES(data), sort_order = VALUES(sort_order);
INSERT INTO collection_items (id, section, data, sort_order) VALUES (53, 'certificates', '{"image":"/uploads/certificate3.png","title":"Appreciation for Outstanding Contribution","issuer":"Military Engineer Service — Commander Works Engineer, Delhi Cantt","date":"May 2026","description":"Col Vidyut Mahato applauds the Trust''s free NDA coaching for aspiring candidates, free library facilities and free coaching classes for students of Class 6th to 12th, making quality education accessible to all sections of society."}', 2) ON DUPLICATE KEY UPDATE data = VALUES(data), sort_order = VALUES(sort_order);
INSERT INTO collection_items (id, section, data, sort_order) VALUES (54, 'certificates', '{"image":"/uploads/certificate4.png","title":"Appreciation Letter for G-20 Volunteering","issuer":"Delhi Police — Asstt. Commissioner of Police, South West District","date":"2023","description":"Recognises the exemplary volunteering services rendered by Trust members during the G-20 Summit, along with its splendid work in education — free tuition with study material and free books and coaching for Class X and XII students."}', 3) ON DUPLICATE KEY UPDATE data = VALUES(data), sort_order = VALUES(sort_order);
INSERT INTO collection_items (id, section, data, sort_order) VALUES (55, 'certificates', '{"image":"/uploads/certificate5.png","title":"Gratitude for G-20 Summit Support","issuer":"Border Security Force — 45 Bn BSF","date":"2023","description":"The BSF places on record its appreciation for the exceptional arrangements — fans, tentage, tables, chairs and water tanks — that kept the troops comfortable during the G-20 Summit 2023."}', 4) ON DUPLICATE KEY UPDATE data = VALUES(data), sort_order = VALUES(sort_order);
INSERT INTO collection_items (id, section, data, sort_order) VALUES (56, 'certificates', '{"image":"/uploads/certificate6.png","title":"Message of Appreciation","issuer":"Virender Singh Kadian — MLA, Govt of NCT of Delhi (Delhi Cantt)","date":"July 2023","description":"The Hon''ble MLA appreciates the Trust''s work for career empowerment of the young generation, environmental development, education and public health across Delhi/NCR, including its dedicated service during the COVID-19 pandemic."}', 5) ON DUPLICATE KEY UPDATE data = VALUES(data), sort_order = VALUES(sort_order);
INSERT INTO collection_items (id, section, data, sort_order) VALUES (57, 'certificates', '{"image":"/uploads/certificate7.png","title":"Blessings & Appreciation","issuer":"Gurdwara Prabandhak Committee (Regd.), Sadar Bazar, Delhi Cantt","date":"February 2023","description":"The Committee lauds the Trust for uplifting society by giving free education, books and uniforms to poor students, along with free eye check-ups and blood donation camps."}', 6) ON DUPLICATE KEY UPDATE data = VALUES(data), sort_order = VALUES(sort_order);
INSERT INTO collection_items (id, section, data, sort_order) VALUES (58, 'certificates', '{"image":"/uploads/certificate8.png","title":"Letter of Appreciation","issuer":"Resident Welfare Association, Village Old Nangal, Delhi Cantt","date":"January 2022","description":"The RWA thanks the Trust for distributing free books and stationery to poor children in slum areas and for its free education, eye-testing camps and blood donation drives."}', 7) ON DUPLICATE KEY UPDATE data = VALUES(data), sort_order = VALUES(sort_order);
