INSERT INTO settings (`key`, data) VALUES ('map', '{"heading":"Find Us on the Map","description":"Visit our office in Sadar Bazar, Delhi Cantt. We are always happy to welcome visitors and volunteers.","embedUrl":"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3503.0892547!2d77.1345!3d28.5963!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x390d1d6f5c5e5e5f%3A0x1a2b3c4d5e6f7890!2sSadar%20Bazar%2C%20Delhi%20Cantt%2C%20New%20Delhi!5e0!3m2!1sen!2sin!4v1710000000000!5m2!1sen!2sin"}') ON DUPLICATE KEY UPDATE data = VALUES(data);
INSERT INTO settings (`key`, data) VALUES ('certificatesSection', '{"heading":"Honours & Recognition","description":"Punjabi Welfare Trust''s service to society has been recognised by Delhi Police, the Indian Army, BSF and community institutions.","archiveHeading":"Our Certificates & Appreciation Letters","archiveDescription":"Every letter here represents years of ground work — education, relief drives, health camps and community service — recognised by government bodies, armed forces and community institutions."}') ON DUPLICATE KEY UPDATE data = VALUES(data);
